import { motion, AnimatePresence } from "framer-motion";
import { Search, ChevronDown, Plus } from "lucide-react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const LinkShow = ({
  search,
  setSearch,
  sort,
  setSort,
  sortOptions,
  dropdownOpen,
  setDropdownOpen,
  dropdownRef,
  setView,
}) => {
  return (
    <div className="space-y-6">

      {/* Top Bar */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">

        {/* Search */}
        <div className="flex items-center gap-3 bg-slate-100 px-4 py-2 rounded-xl w-full sm:w-72 focus-within:ring-2 focus-within:ring-slate-400 transition">
          <Search size={16} />
          <input
            type="text"
            placeholder="Search link..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="bg-transparent outline-none text-xs sm:text-sm w-full text-slate-700 placeholder:text-slate-400"
          />
        </div>

        {/* Add Button */}
        <button
          onClick={() => setView("add")}
          className="inline-flex items-center justify-center gap-2 bg-gradient-to-r from-slate-600 to-slate-800 hover:from-slate-700 hover:to-slate-900 text-white px-5 py-2 rounded-xl text-xs sm:text-sm md:text-base font-medium shadow-sm hover:shadow-md transition-all w-full sm:w-auto"
        >
          <Plus size={16} />
          Add Link
        </button>

      </div>

      {/* Table */}
      <div className={design.table}>

        {/* Title + Sort */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between px-4 sm:px-6 py-4 border-b border-slate-200 bg-slate-50 gap-3">

          <h2 className="text-sm sm:text-base md:text-lg font-semibold text-slate-800">
            Parent Links List
          </h2>

          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setDropdownOpen(!dropdownOpen)}
              className="flex items-center gap-2 text-xs sm:text-sm bg-white border border-slate-300 px-4 py-2 rounded-xl shadow-sm hover:shadow-md transition"
            >
              {sortOptions.find((o) => o.value === sort)?.label}
              <ChevronDown size={14} />
            </button>

            <AnimatePresence>
              {dropdownOpen && (
                <motion.div
                  initial={{ opacity: 0, y: -6 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0 }}
                  className="absolute right-0 mt-2 w-44 bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden z-50"
                >
                  {sortOptions.map((option) => (
                    <div
                      key={option.value}
                      onClick={() => {
                        setSort(option.value);
                        setDropdownOpen(false);
                      }}
                      className={`px-4 py-2 text-xs sm:text-sm hover:bg-slate-100 cursor-pointer ${
                        sort === option.value
                          ? "bg-slate-100 font-semibold"
                          : ""
                      }`}
                    >
                      {option.label}
                    </div>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

        </div>

        {/* Responsive Table Scroll */}
        <div className="overflow-x-auto">
          <div className="min-w-[600px]">

            <div className="grid grid-cols-4 items-center px-4 sm:px-6 py-3 text-xs sm:text-sm font-semibold text-slate-600">
              <div>#</div>
              <div>Name</div>
              <div>Status</div>
              <div className="text-right">Actions</div>
            </div>

            {/* Dummy row example */}
            <div className={design.row}>
              <div>1</div>
              <div>Home</div>
              <div>Active</div>
              <div className="text-right">Edit | Delete</div>
            </div>

          </div>
        </div>

      </div>

    </div>
  );
};

export default LinkShow;
